import { trpc } from '@/trpc/client';

function ChatStream() {
  const streamQuery = trpc.chatStream.useQuery('Hello AI');

  if (streamQuery.isLoading && !streamQuery.data) {
    return <p>Loading...</p>;
  }

  if (streamQuery.error) {
