  return <p id="stream-output">{text || 'Waiting for stream...'}</p>;
}

export default function Home() {
  return (
    <main className="p-4">
      <h1 className="text-2xl font-bold mb-4">tRPC AI Streaming Chat</h1>
      <ChatStream />
    </main>
  );
}

